const configRows = $input.all();
const categories = [];

for (const row of configRows) {
  const field = row.json.field || '';
  const content = row.json.content || '';
  const categoriesList = row.json.categories_list || '';

  if (field.includes('smartsheet ID')) {
    const categoryGroup = field.replace(' smartsheet ID', '').toLowerCase();
    const cats = categoriesList.split(',').map(c => c.trim().toLowerCase()).filter(Boolean);

    if (content && cats.length > 0) {
      categories.push({
        json: {
          category_group: categoryGroup,
          smartsheet_id: content,
          categories: cats,
          imported_games_sheet: categoryGroup
        }
      });
    }
  }
}

return categories;

