const columns = $json.data || [];
const gameData = $('If').first().json;
const games = gameData.games;
const colByTitle = Object.fromEntries(columns.map(c => [String(c.title).trim(), c.id]));

function pushCell(cells, t, v) { const id = colByTitle[t]; if (id && v != null && v !== '') cells.push({ columnId: String(id), value: v, strict: false }); }
function toDateYMD(v) { if (!v) return v; const d = new Date(v); if (isNaN(d.getTime())) return String(v); return `${d.getUTCFullYear()}-${String(d.getUTCMonth()+1).padStart(2,'0')}-${String(d.getUTCDate()).padStart(2,'0')}`; }
function catAt(cats, idx) { if (Array.isArray(cats)) return cats[idx]; if (typeof cats === 'string') return cats.split(/[;,|]/).map(s=>s.trim()).filter(Boolean)[idx]; return undefined; }

const rows = games.map(g => {
  const cells = [];
  const os = String(g.os || '').toLowerCase();
  pushCell(cells, 'Game Name', (g.title || '').replace(/:/g, '').trim());
  pushCell(cells, 'Release Date', toDateYMD(g.initial_release));
  pushCell(cells, 'GameID', g.game_id);
  pushCell(cells, 'Genre 1', catAt(g.categories, 0));
  pushCell(cells, 'Genre 2', catAt(g.categories, 1));
  pushCell(cells, 'Created', toDateYMD(g.created_date));
  pushCell(cells, 'Import Date', toDateYMD(new Date()));
  if (os === 'ios') { pushCell(cells, 'IOS Link', g.app_link); pushCell(cells, 'Publisher Name (IOS)', g.publisher_name); }
  else { pushCell(cells, 'AND Link', g.app_link); pushCell(cells, 'Publisher Name (AND)', g.publisher_name); }
  return { toTop: true, cells };
});

return [{ json: { rows, category: 'puzzle', count: games.length, smartsheet_id: gameData.smartsheet_id, game_ids: games.map(g => g.game_id) } }];

