const items = $input.all();
let puzzleCount = 0, arcadeCount = 0, simulationCount = 0;
let puzzleError = false, arcadeError = false, simulationError = false;
let puzzleErrorMsg = '', arcadeErrorMsg = '', simulationErrorMsg = '';
for (const item of items) {
  const cat = item.json.category;
  const count = item.json.count || 0;
  const hasError = item.json.error === true;
  const errorMsg = item.json.error_message || '';
  if (cat === 'puzzle') { puzzleCount = count; puzzleError = hasError; puzzleErrorMsg = errorMsg; }
  else if (cat === 'arcade') { arcadeCount = count; arcadeError = hasError; arcadeErrorMsg = errorMsg; }
  else if (cat === 'simulation') { simulationCount = count; simulationError = hasError; simulationErrorMsg = errorMsg; }
}
const total = puzzleCount + arcadeCount + simulationCount;
const hasAnyError = puzzleError || arcadeError || simulationError;
const puzzleDisplay = puzzleError ? '⛔ ' + puzzleErrorMsg : String(puzzleCount);
const arcadeDisplay = arcadeError ? '⛔ ' + arcadeErrorMsg : String(arcadeCount);
const simulationDisplay = simulationError ? '⛔ ' + simulationErrorMsg : String(simulationCount);
return [{ json: { puzzle_count: puzzleCount, arcade_count: arcadeCount, simulation_count: simulationCount, total_count: total, puzzle_display: puzzleDisplay, arcade_display: arcadeDisplay, simulation_display: simulationDisplay, has_error: hasAnyError } }];

